-                    new_g = @truncate(((@as(u16, curr_g) * a16) + (@as(u16, bg_g) * inv_a)) / 255);
-                    new_b = @truncate(((@as(u16, curr_b) * a16) + (@as(u16, bg_b) * inv_a)) / 255);
