-            const prev_a = bgra_prev[bgra_idx + 3];
-
-            if (curr_b == prev_b and curr_g == prev_g and curr_r == prev_r and curr_a == prev_a) {
-                continue;
-            }
-
-            var new_r: u8 = undefined;
-            var new_g: u8 = undefined;
-            var new_b: u8 = undefined;
-            if (curr_a == 255) {
-                new_r = curr_r;
